import { Grid } from "./Grid";
import { Box } from "../Box";

export default {
  title: "Layout/Grid",
  component: Grid,
  tags: ["autodocs"],
  parameters: {
    layout: "padded",
    docs: {
      description: {
        component: "Grid component for creating CSS Grid layouts.",
      },
    },
  },
  argTypes: {
    gap: {
      control: "select",
      options: ["1", "2", "3", "4", "5", "6", "8", "10"],
      description: "Gap between grid items",
    },
    templateColumns: {
      control: "text",
      description: "CSS grid-template-columns value",
    },
    templateRows: {
      control: "text",
      description: "CSS grid-template-rows value",
    },
  },
};

export const BasicGrid = {
  args: {
    templateColumns: "repeat(3, 1fr)",
    gap: "6",
  },
  render: (args) => (
    <Grid {...args}>
      <Box h="20" bg="primary.500" borderRadius="md" />
      <Box h="20" bg="primary.500" borderRadius="md" />
      <Box h="20" bg="primary.500" borderRadius="md" />
    </Grid>
  ),
};

